import { Hono } from 'hono';
import Stripe from 'stripe';
import { config } from './config';
import { CreateSubscriptionRequestBody } from './types';

// Initialize Stripe with the secret key from environment variables.
// The API version is important for compatibility.
const stripe = new Stripe(config.stripeSecretKey!, {
  apiVersion: '2023-10-16', // Use a recent stable API version
});

const app = new Hono();

/**
 * POST /subscribe
 * Creates a new Stripe subscription for a given customer and price.
 *
 * Request Body:
 * {
 *   "customerId": "cus_xxxxxxxxxxxxxx",
 *   "priceId": "price_xxxxxxxxxxxxxx"
 * }
 *
 * Response:
 * {
 *   "message": "Subscription created successfully",
 *   "subscriptionId": "sub_xxxxxxxxxxxxxx"
 * }
 */
app.post('/subscribe', async (c) => {
  try {
    const body: CreateSubscriptionRequestBody = await c.req.json();
    const { customerId, priceId } = body;

    // Basic input validation
    if (!customerId || typeof customerId !== 'string') {
      return c.json({ error: 'Invalid or missing customerId' }, 400);
    }
    if (!priceId || typeof priceId !== 'string') {
      return c.json({ error: 'Invalid or missing priceId' }, 400);
    }

    // Create the Stripe subscription
    const subscription = await stripe.subscriptions.create({
      customer: customerId,
      items: [{ price: priceId }],
      // You might add more options here, e.g., collection_method, default_payment_method, etc.
      // For simplicity, we're using the customer's default payment method.
    });

    // In a real application, you would store `subscription.id` in your database
    // associated with the user. For this exercise, we'll just return it.
    return c.json({
      message: 'Subscription created successfully',
      subscriptionId: subscription.id,
    }, 201);

  } catch (error: any) {
    // Handle Stripe-specific errors
    if (error.type === 'StripeCardError' || error.type === 'StripeInvalidRequestError') {
      return c.json({ error: error.message }, 400);
    }
    // Handle other unexpected errors
    console.error('Error creating subscription:', error);
    return c.json({ error: 'Failed to create subscription', details: error.message }, 500);
  }
});

// Optional: A simple health check route
app.get('/', (c) => {
  return c.text('Stripe Subscription Service is running!');
});

export default app;
```

